watch(() => arrivedState.bottom, () => {
  if (arrivedState.bottom && canLoadMore.value) {
    loadMore()
  }
})

export const defu = createDefu((obj, key, value) => {
  if (Array.isArray(obj[key]) && Array.isArray(value)) {
    obj[key] = value
    return true
  }
})

if ((shape[property] as Draft07DefinitionPropertyAnyOf).anyOf) {
  if (((shape[property] as Draft07DefinitionPropertyAnyOf).anyOf).find(t => t.type === 'null')) {
    result.nullable = true
  }
}

if ((shape[property] as Draft07DefinitionPropertyOneOf).oneOf) {
  if (((shape[property] as Draft07DefinitionPropertyOneOf).oneOf).find(t => t.type === 'null')) {
    result.nullable = true
  }
}

if (wantContentSnippet) {
  selectClause += `, snippet(${FTS_TABLE}, 5, '${pre}', '${post}', '...', ${around}) as snippet_content`
}

if (from !== `_content_${collection}`) {
  const collection = String(from || '').replace(/^_content_/, '')
  throw new Error(`Invalid query: Collection '${collection}' does not exist`)
}

for (const layer of ctx.i18nLayers) {
  if (layer.i18n.locales == null) { continue }
  configs.push(assign({}, layer.i18n, { langDir: resolve(layer.i18nDir, layer.i18n.langDir ?? 'locales'), locales: layer.i18n.locales }))
}

i18n.te = (key, locale) => {
  serverI18n?.trackKey(key, locale || ctx.getLocale())
  return originalTe(key, locale)
}

if (!baseUrl && !__DIFFERENT_DOMAINS__ && !__MULTI_DOMAIN_LOCALES__) {
  if (__I18N_STRICT_SEO__) {
    throw new Error('I18n `baseUrl` is required to generate valid SEO tag links.')
  }
  console.warn('I18n `baseUrl` is required to generate valid SEO tag links.')
}

if (!__I18N_ROUTING__ && !__DIFFERENT_DOMAINS__) {
  return routeName => normalizeRouteName(routeName)
}

if (__I18N_STRATEGY__ === 'prefix_and_default') {
  return (name, locale) => getLocalizedRouteName(normalizeRouteName(name), locale, locale === defaultLocale)
}

const getDomainFromLocale = (event: H3Event, locale: string) => {
  if (!__MULTI_DOMAIN_LOCALES__ && !__DIFFERENT_DOMAINS__) { return }
  return domainFromLocale(runtimeI18n.domainLocales, getRequestURL(event, { xForwardedHost: true }), locale)
}

export const getAllMergedMessages = cachedFunctionI18n(_getAllMergedMessages, {
  name: 'merged-all',
  maxAge: !__I18N_CACHE__ ? -1 : 60 * 60 * 24,
  getKey: locales => locales.join('-'),
  shouldBypassCache: locales => !locales.every(locale => isLocaleCacheable(locale)),
})

const TOC_TAGS_DEPTH = TOC_TAGS.reduce((tags: any, tag: string) => {
  tags[tag] = Number(tag.charAt(tag.length - 1))
  return tags
}, {})

watch(data, (val) => {
  if (val?.siteConfig?.url)
    productionUrl.value = val.siteConfig.url
}, { immediate: true })

Object.entries(definition).forEach(([key, value]) => {
  if (value !== undefined && (!Array.isArray(value) || value.length > 0) && key !== 'includeAppSources')
    options[key] = value
})

const totalProductionUrls = computed(() =>
  productionData.value?.sitemaps.reduce((sum, s) => sum + s.urlCount, 0) ?? 0,
)

if (credits) {
  xmlParts.push(`<!-- XML Sitemap Index generated by @nuxtjs/sitemap v${version} at ${new Date().toISOString()} -->`)
}

if (import.meta.dev && url._warnings?.length) {
  for (const w of url._warnings)
    xml += `${I2}<!-- WARN: ${w} -->${NL}`
}

if (credits) {
  xml += `${NL}<!-- XML Sitemap generated by @nuxtjs/sitemap v${version} at ${new Date().toISOString()} -->`
}

if (url.priority !== undefined) {
  const p = typeof url.priority === 'number' ? url.priority : Number.parseFloat(url.priority)
  xml += `${I2}<priority>${p.toFixed(1)}</priority>${NL}`
}

if (typeof value === 'string' && value.trim()) {
  const num = Number.parseInt(value.trim(), 10)
  return Number.isNaN(num) ? undefined : num
}
